-- =============================================================================-- CIRCLE BUILDER SUITE: COMPACT MASTER Matrix (FIXED RE-MERGED RUNNER)-- =============================================================================local Players = game:GetService("Players")local CoreGui = game:GetService("CoreGui")local RunService = game:GetService("RunService")local UserInputService = game:GetService("UserInputService")local LocalPlayer = Players.LocalPlayerlocal Mouse = LocalPlayer:GetMouse()local dataFolder = LocalPlayer:WaitForChild("Data", 5)if CoreGui:FindFirstChild("CircleBuilderUI") then CoreGui.CircleBuilderUI:Destroy() end-- INTERFACE INITIALIZATIONlocal ScreenGui = Instance.new("ScreenGui", CoreGui) ScreenGui.Name = "CircleBuilderUI" ScreenGui.ResetOnSpawn = falselocal MainFrame = Instance.new("Frame", ScreenGui) MainFrame.Size = UDim2.new(0, 330, 0, 560) MainFrame.Position = UDim2.new(0.05, 0, 0.15, 0) MainFrame.BackgroundColor3 = Color3.fromRGB(28, 28, 32) MainFrame.Active = true MainFrame.Draggable = true Instance.new("UICorner", MainFrame).CornerRadius = UDim.new(0, 12)local ReopenButton = Instance.new("TextButton", ScreenGui) ReopenButton.Size = UDim2.new(0, 120, 0, 40) ReopenButton.Position = UDim2.new(0, 10, 0.5, -20) ReopenButton.Text = "Open Builder" ReopenButton.TextColor3 = Color3.fromRGB(255, 255, 255) ReopenButton.BackgroundColor3 = Color3.fromRGB(38, 38, 44) ReopenButton.Font = Enum.Font.GothamBold ReopenButton.TextSize = 13 ReopenButton.Visible = false Instance.new("UICorner", ReopenButton).CornerRadius = UDim.new(0, 6)local Title = Instance.new("TextLabel", MainFrame) Title.Size = UDim2.new(1, 0, 0, 45) Title.Text = "  CIRCLE BUILDER SUITE" Title.TextColor3 = Color3.fromRGB(255, 255, 255) Title.Font = Enum.Font.GothamBold Title.BackgroundColor3 = Color3.fromRGB(38, 38, 44) Title.TextXAlignment = Enum.TextXAlignment.Left Instance.new("UICorner", Title).CornerRadius = UDim.new(0, 12)local CloseBtn = Instance.new("TextButton", MainFrame) CloseBtn.Size = UDim2.new(0, 30, 0, 30) CloseBtn.Position = UDim2.new(1, -40, 0, 7) CloseBtn.Text = "X" CloseBtn.TextColor3 = Color3.fromRGB(240, 90, 90) CloseBtn.BackgroundColor3 = Color3.fromRGB(48, 48, 54) CloseBtn.Font = Enum.Font.GothamBold Instance.new("UICorner", CloseBtn).CornerRadius = UDim.new(0, 6)-- GENERATE GENERATIVE LABELS & ENTRIES WITH FIXED COMPACT GEOMETRYlocal function addInput(labelText, yPos, defaultValue, editable)local lbl = Instance.new("TextLabel", MainFrame) lbl.Size = UDim2.new(0, 150, 0, 28) lbl.Position = UDim2.new(0, 15, 0, yPos) lbl.Text = labelText lbl.TextColor3 = Color3.fromRGB(190, 190, 195) lbl.TextSize = 13 lbl.TextXAlignment = Enum.TextXAlignment.Left lbl.BackgroundTransparency = 1 lbl.Font = Enum.Font.Gothamlocal box = Instance.new("TextBox", MainFrame) box.Size = UDim2.new(0, 130, 0, 28) box.Position = UDim2.new(0, 175, 0, yPos) box.Text = defaultValue box.TextColor3 = Color3.fromRGB(255, 255, 255) box.BackgroundColor3 = Color3.fromRGB(44, 44, 50) box.Font = Enum.Font.GothamSemibold box.TextSize = 13 box.TextEditable = editable Instance.new("UICorner", box).CornerRadius = UDim.new(0, 5)return boxendlocal inputRadius = addInput("Circle Radius / Range:", 55, "20", true)local inputSteps = addInput("Total Parts Count:", 97, "30", true)local inputSizeY = addInput("Block Height (Y):", 139, "2", true)local inputBlockType = addInput("Active Block Type:", 181, "PlasticBlock", true)local inputSizeX = addInput("Calculated Width (X):", 223, "0.00", false)local inputSizeZ = addInput("Calculated Depth (Z):", 265, "0.00", false)-- BUTTON SECTIONS (PERFECT SPACING LAYOUTS TO COMPENSATE FOR UI COLLISIONS)local statusLabel = Instance.new("TextLabel", MainFrame) statusLabel.Size = UDim2.new(1, -30, 0, 30) statusLabel.Position = UDim2.new(0, 15, 0, 310) statusLabel.Text = "Center Target Block: Not Selected" statusLabel.TextColor3 = Color3.fromRGB(240, 90, 90) statusLabel.TextSize = 12 statusLabel.Font = Enum.Font.GothamSemibold statusLabel.BackgroundTransparency = 1local function createButton(text, yPos, color)local btn = Instance.new("TextButton", MainFrame) btn.Size = UDim2.new(1, -30, 0, 36) btn.Position = UDim2.new(0, 15, 0, yPos) btn.Text = text btn.TextColor3 = Color3.fromRGB(255, 255, 255) btn.TextSize = 12 btn.Font = Enum.Font.GothamBold btn.BackgroundColor3 = color btn.BorderSizePixel = 0 Instance.new("UICorner", btn).CornerRadius = UDim.new(0, 6)return btnendlocal btnSelect = createButton("Select Center Target Block", 345, Color3.fromRGB(0, 122, 215))local btnPreview = createButton("Hologram Preview Configuration: Disabled", 388, Color3.fromRGB(110, 110, 115))local btnBuild = createButton("Commence Circle Construction", 431, Color3.fromRGB(46, 139, 87))-- POPUP BLOCK SELECTOR DRAWER PANEL MENU Setuplocal BlockPanel = Instance.new("Frame", MainFrame) BlockPanel.Size = UDim2.new(0, 240, 1, 0) BlockPanel.Position = UDim2.new(1, 10, 0, 0) BlockPanel.BackgroundColor3 = Color3.fromRGB(34, 34, 38) BlockPanel.Visible = false Instance.new("UICorner", BlockPanel).CornerRadius = UDim.new(0, 10)local PanelTitle = Instance.new("TextLabel", BlockPanel) PanelTitle.Size = UDim2.new(1, 0, 0, 40) PanelTitle.Text = "AVAILABLE BUILDING MATERIALS" PanelTitle.TextColor3 = Color3.fromRGB(255, 255, 255) PanelTitle.Font = Enum.Font.GothamBold PanelTitle.BackgroundColor3 = Color3.fromRGB(44, 44, 50) Instance.new("UICorner", PanelTitle).CornerRadius = UDim.new(0, 10)local ScrollingFrame = Instance.new("ScrollingFrame", BlockPanel) ScrollingFrame.Size = UDim2.new(1, -20, 1, -60) ScrollingFrame.Position = UDim2.new(0, 10, 0, 50) ScrollingFrame.BackgroundTransparency = 1 ScrollingFrame.ScrollBarThickness = 4 ScrollingFrame.AutomaticCanvasSize = Enum.AutomaticSize.Ylocal UIListLayout = Instance.new("UIListLayout", ScrollingFrame) UIListLayout.Padding = UDim.new(0, 4) UIListLayout.SortOrder = Enum.SortOrder.Name-- INTERFACE UTILITIES CONNECTIONSCloseBtn.MouseButton1Click:Connect(function() MainFrame.Visible = false ReopenButton.Visible = true BlockPanel.Visible = false end)ReopenButton.MouseButton1Click:Connect(function() MainFrame.Visible = true ReopenButton.Visible = false end)inputBlockType.Focused:Connect(function() BlockPanel.Visible = true end)local function updateInventoryLayout()for _, child in ipairs(ScrollingFrame:GetChildren()) do if child:IsA("TextButton") then child:Destroy() end endif not dataFolder then return endfor _, item in ipairs(dataFolder:GetChildren()) doif item:IsA("ValueBase") and item.Value > 0 and not string.find(item.Name, "Tool") thenlocal itemBtn = Instance.new("TextButton", ScrollingFrame) itemBtn.Size = UDim2.new(1, -5, 0, 30) itemBtn.Text = "  " .. item.Name .. " (" .. tostring(item.Value) .. ")" itemBtn.TextColor3 = Color3.fromRGB(190, 190, 195) itemBtn.BackgroundColor3 = Color3.fromRGB(44, 44, 50) itemBtn.Font = Enum.Font.GothamSemibold itemBtn.TextSize = 11 itemBtn.TextXAlignment = Enum.TextXAlignment.Left Instance.new("UICorner", itemBtn).CornerRadius = UDim.new(0, 4)itemBtn.MouseButton1Click:Connect(function() inputBlockType.Text = item.Name BlockPanel.Visible = false updateInventoryLayout() end)endendendif dataFolder thenupdateInventoryLayout() dataFolder.ChildAdded:Connect(updateInventoryLayout)dataFolder.ChildRemoved:Connect(updateInventoryLayout)end-- 3D BLUEPRINT MATRIX CALCULATION LOGIClocal previewFolder = workspace:FindFirstChild("CirclePreviewFolder") or Instance.new("Folder", workspace) previewFolder.Name = "CirclePreviewFolder"local selectionBox = Instance.new("SelectionBox", CoreGui) selectionBox.Color3 = Color3.fromRGB(0, 255, 255) selectionBox.LineThickness = 0.04local selectedCenterPos, isSelecting, showLivePreview = nil, false, falselocal function updateRingVisuals()previewFolder:ClearAllChildren()if not selectedCenterPos then return endlocal radius, steps, sizeY = tonumber(inputRadius.Text) or 20, tonumber(inputSteps.Text) or 30, tonumber(inputSizeY.Text) or 2local sizeZ = (2 * math.pi * radius) / stepslocal sizeX = (2 * radius * math.tan(math.pi / steps)) + 0.02inputSizeX.Text, inputSizeZ.Text = string.format("%.3f", sizeX), string.format("%.3f", sizeZ)if not showLivePreview then return endfor i = 1, steps dolocal angle = (i / steps) * math.pi * 2local p = Vector3.new(selectedCenterPos.X + math.cos(angle) * radius, selectedCenterPos.Y, selectedCenterPos.Z + math.sin(angle) * radius)local hp = Instance.new("Part", previewFolder) hp.Size = Vector3.new(sizeX, sizeY, sizeZ) hp.CFrame = CFrame.lookAt(p, selectedCenterPos) hp.Color = Color3.new(1,1,1) hp.Transparency = 0.5 hp.Anchored = true hp.CanCollide = falselocal sb = Instance.new("SelectionBox", hp) sb.Adornee = hp sb.Color3 = Color3.fromRGB(0, 255, 255) sb.LineThickness = 0.01endendfor _, box in ipairs({inputRadius, inputSteps, inputSizeY}) do box:GetPropertyChangedSignal("Text"):Connect(updateRingVisuals) end-- BUTTON CLICKS IMPLEMENTATIONbtnSelect.MouseButton1Click:Connect(function()if isSelecting then return end isSelecting = truestatusLabel.Text, btnSelect.Text = "Select an anchor object Node...", "Awaiting Node Target..."local rConn, cConnrConn = RunService.RenderStepped:Connect(function() selectionBox.Adornee = Mouse.Target end)cConn = Mouse.Button1Down:Connect(function()local t = Mouse.Target if t and t:IsA("BasePart") thenselectedCenterPos = t.Position statusLabel.Text = "Target Locked: " .. t.Name statusLabel.TextColor3 = Color3.fromRGB(80, 240, 80)rConn:Disconnect() cConn:Disconnect() selectionBox.Adornee = nil isSelecting = false btnSelect.Text = "Select Center Target Block" updateRingVisuals()endend)end)btnPreview.MouseButton1Click:Connect(function()showLivePreview = not showLivePreviewbtnPreview.Text = showLivePreview and "Hologram Preview Configuration: Active" or "Hologram Preview Configuration: Disabled"btnPreview.BackgroundColor3 = showLivePreview and Color3.fromRGB(155, 80, 180) or Color3.fromRGB(110, 110, 115)updateRingVisuals()end)btnBuild.MouseButton1Click:Connect(function()if isSelecting or not selectedCenterPos then return endlocal blockStr = tostring(inputBlockType.Text)local inventoryItem = dataFolder and dataFolder:FindFirstChild(blockStr)if not inventoryItem or inventoryItem.Value <= 0 then statusLabel.Text = "Build Failed: Out of Blocks!" statusLabel.TextColor3 = Color3.fromRGB(255,80,80) return endlocal radius, steps, sizeY = tonumber(inputRadius.Text) or 20, tonumber(inputSteps.Text) or 30, tonumber(inputSizeY.Text) or 2local sizeZ = (2 * math.pi * radius) / steps local sizeX = (2 * radius * math.tan(math.pi / steps)) + 0.02local function getRF(n) local tl = LocalPlayer.Backpack:FindFirstChild(n) or (LocalPlayer.Character and LocalPlayer.Character:FindFirstChild(n)) return tl and tl:FindFirstChild("RF") endlocal bRF, sRF, pRF = getRF("BuildingTool"), getRF("ScalingTool"), getRF("PaintingTool")if not bRF or not sRF or not pRF then statusLabel.Text = "Missing Tools!" return endpreviewFolder:ClearAllChildren() BlockPanel.Visible = false btnBuild.Text, btnBuild.Active = "Constructing Active Sector Matrix...", falselocal folder = workspace:WaitForChild("Blocks", 5):WaitForChild(LocalPlayer.Name, 5)for i = 1, steps doif inventoryItem.Value <= 0 then statusLabel.Text = "Stopped: Empty Inventory!" statusLabel.TextColor3 = Color3.fromRGB(255,80,80) break endlocal angle = (i / steps) * math.pi * 2local p = Vector3.new(selectedCenterPos.X + math.cos(angle) * radius, selectedCenterPos.Y, selectedCenterPos.Z + math.sin(angle) * radius)local pCF, hCF = CFrame.lookAt(p, selectedCenterPos), CFrame.new(p) * CFrame.Angles(0, angle, 0)local initialCount = #folder:GetChildren()-- PASSES DYNAMIC TEXT BOX MATERIAL NAME & ITS MATCHING VAL FROM YOUR LIVE DATA INVENTORY FOLDERbRF:InvokeServer(blockStr, inventoryItem.Value, Instance.new("Part", nil), pCF, true, hCF, false)local newBlock, loops = nil, 0while not newBlock and loops < 30 do task.wait(0.01) if #folder:GetChildren() > initialCount then newBlock = folder:GetChildren()[#folder:GetChildren()] end loops = loops + 1 endif newBlock thensRF:InvokeServer(newBlock, Vector3.new(sizeX, sizeY, sizeZ), pCF) task.wait(0.01)pRF:InvokeServer({{{ newBlock, Color3.new(1,1,1) }, { newBlock, Color3.new(1,1,1) }, { newBlock, Color3.new(1,1,1) }, { newBlock, Color3.new(1,1,1) }}})endtask.wait(0.02)endbtnBuild.Text, btnBuild.Active = "Commence Circle Construction", trueif statusLabel.Text ~= "Stopped: Empty Inventory!" then statusLabel.Text = "Matrix Sequence Completed!" statusLabel.TextColor3 = Color3.fromRGB(80, 240, 80) endend)
